def test_model_name_defaults_to_gemini_flash():
    from api.ai import _model_name
    assert _model_name({}) == "gemini-2.5-flash"

def test_model_name_returns_override_from_settings():
    from api.ai import _model_name
    assert _model_name({"llm_model": "gemini-2.0-pro"}) == "gemini-2.0-pro"

def test_read_meta_returns_empty_dict_when_file_missing(tmp_path):
    from api.vault import _read_meta
    result = _read_meta(str(tmp_path / "nonexistent"))
    assert result == {}

def test_read_meta_returns_parsed_json(tmp_path):
    from api.vault import _read_meta
    meta = {"embedding_model": "models/gemini-embedding-001", "doc_count": 5}
    (tmp_path / "db_meta.json").write_text(json.dumps(meta))
    assert _read_meta(str(tmp_path)) == meta

def test_read_meta_returns_empty_dict_on_corrupt_json(tmp_path):
    from api.vault import _read_meta
    (tmp_path / "db_meta.json").write_text("NOT JSON {{{")
    assert _read_meta(str(tmp_path)) == {}

def test_should_refine_draft_content(client, db_path, mock_gemini, settings):
    mock_gemini.models.generate_content.return_value.text = "Shorter version."
    with patch("api.db.DB_PATH", db_path):
        from api.db import save_settings
        save_settings(settings)
    resp = client.post("/api/draft/refine", json={
        "content": "Long original content.", "action": "shorten", "channel": "Press Release"
    })
    assert resp.status_code == 200
    assert resp.json()["content"] == "Shorter version."


def test_should_return_500_when_refine_raises(client, db_path, settings):
    with patch("api.db.DB_PATH", db_path):
        from api.db import save_settings
        save_settings(settings)
    with patch("api.ai.refine", side_effect=Exception("Refine failure")):
        resp = client.post("/api/draft/refine", json={
            "content": "text", "action": "shorten", "channel": "LinkedIn"
        })
    assert resp.status_code == 500
    assert "error" in resp.json()
